class Solution {
    public int maximumCostSubstring(String s, String chars, int[] vals) {
        int[] charVals = new int[26];
        for (int i = 0; i < 26; i++) {
            charVals[i] = i + 1;
        }
        for (int i = 0; i < chars.length(); i++) {
            charVals[chars.charAt(i) - 'a'] = vals[i];
        }
        int maxCost = 0, currCost = 0;
        for (char c : s.toCharArray()) {
            currCost = Math.max(charVals[c - 'a'], currCost + charVals[c - 'a']);
            maxCost = Math.max(maxCost, currCost);
        }
        return maxCost;
    }
}
efficiency: HIGH
time complexity: O(n + m)
space complexity: O(1)
energy implications: LOW
explanation: Uses Kadane's algorithm to track maximum cost substring, mapping character values efficiently.
